exercises.solution_code:
#include <array>
#include <iostream>
#include <string_view>

struct Student
{
    std::string_view name{};
    int grade{};
};

int main()
{
    constexpr std::array<Student, 4> roster {
        Student{"Alice", 92},
        Student{"Bob", 85},
        Student{"Carol", 97},
        Student{"Dave", 78}
    };

    int index{};
    std::cin >> index;

    if (index < 0 || index >= static_cast<int>(roster.size()))
    {
        std::cout << "Invalid index" << '\n';
        return 0;
    }

    std::cout << roster[static_cast<std::size_t>(index)].name
              << " has grade "
              << roster[static_cast<std::size_t>(index)].grade << '\n';

    return 0;
}

