exercises.solution_code:
#include <array>
#include <iostream>
#include <string_view>

struct Rect
{
    std::string_view name{};
    int width{};
    int height{};
};

int main()
{
    constexpr std::array<Rect, 5> rects {
        Rect{"A", 3, 4},
        Rect{"B", 10, 2},
        Rect{"C", 1, 1},
        Rect{"D", 5, 5},
        Rect{"E", 2, 3}
    };

    int threshold{};
    std::cin >> threshold;

    bool found{ false };
    for (const auto& r : rects)
    {
        int area{ r.width * r.height };
        if (area >= threshold)
        {
            std::cout << r.name << ": " << area << '\n';
            found = true;
        }
    }

    if (!found)
        std::cout << "None" << '\n';

    return 0;
}
